// ─────────────────────────────────────────────────────────────
// VALIDATE & FINGERPRINT
// Pure-JS hash (no require('crypto') — banned in n8n sandbox)
// ─────────────────────────────────────────────────────────────
const item = items[0];

const fileName   = item.json.name || item.json.fileName || 'unknown';
const mimeType   = item.json.mimeType || '';
const fileSize   = item.json.size || 0;
const driveFileId = item.json.id || '';

// Determine file type from mime or extension
let fileType = 'unknown';
if (mimeType.includes('pdf') || fileName.toLowerCase().endsWith('.pdf')) fileType = 'pdf';
else if (mimeType.includes('word') || mimeType.includes('openxmlformats') ||
         fileName.toLowerCase().endsWith('.docx') || fileName.toLowerCase().endsWith('.doc')) fileType = 'docx';

// Reject unsupported types
if (fileType === 'unknown') {
  throw new Error(`Unsupported file type: ${mimeType} (${fileName})`);
}

// Pure-JS fingerprint — djb2 hash on filename+size+timestamp
function djb2(str) {
  let hash = 5381;
  for (let i = 0; i < str.length; i++) {
    hash = ((hash << 5) + hash) + str.charCodeAt(i);
    hash = hash & hash; // 32-bit
  }
  return Math.abs(hash).toString(16).padStart(8, '0');
}
const fileHash = djb2(`${fileName}-${fileSize}-${Date.now()}`);
const sessionId = `contract-${fileHash}-${Date.now()}`;

return [{
  json: {
    ...item.json,
    sessionId,
    fileName,
    fileType,
    fileHash,
    mimeType,
    fileSize,
    driveFileId,
    uploadedAt: new Date().toISOString()
  },
  binary: item.binary
}];

// ─────────────────────────────────────────────────────────────
// MERGE EXTRACTED TEXT
// Both PDF and DOCX branches land here — normalise to documentText
// ─────────────────────────────────────────────────────────────
const item = items[0];

// n8n Extract From File node puts text in item.json.text
const documentText = item.json.text || item.json.content || item.json.data || '';

if (!documentText || documentText.trim().length === 0) {
  throw new Error('Document text extraction failed — empty result.');
}

return [{
  json: {
    ...item.json,
    documentText: documentText.trim()
  }
}];

// ─────────────────────────────────────────────────────────────
// PARSE CLASSIFICATION RESULT
// ─────────────────────────────────────────────────────────────
const item = items[0];

let raw = item.json.output || '';

// Strip markdown code fences if model added them
raw = raw.replace(/```json/gi, '').replace(/```/g, '').trim();

let parsed;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  throw new Error(`Classification parse failed: ${e.message}\nRaw: ${raw.substring(0, 200)}`);
}

return [{
  json: {
    ...item.json,
    contractType: parsed.contractType || 'Unknown',
    confidence:   parsed.confidence   || 0,
    reasoning:    parsed.reasoning    || ''
  }
}];

