// ─────────────────────────────────────────────────────────────
// PARSE: PLAIN ENGLISH
// ─────────────────────────────────────────────────────────────
const item = items[0];

let raw = item.json.output || '';
raw = raw.replace(/```json/gi, '').replace(/```/g, '').trim();

let parsed;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  throw new Error(`Plain English parse failed: ${e.message}\nRaw: ${raw.substring(0, 200)}`);
}

return [{
  json: {
    ...item.json,
    plainEnglishSummary:    parsed.plainEnglishSummary    || '',
    shouldSign:             parsed.shouldSign             || 'NEGOTIATE FIRST',
    topThreeActions:        Array.isArray(parsed.topThreeActions) ? parsed.topThreeActions : [],
    riskBreakdown:          Array.isArray(parsed.riskBreakdown)   ? parsed.riskBreakdown   : [],
    missingProtectionsPlain:Array.isArray(parsed.missingProtectionsPlain) ? parsed.missingProtectionsPlain : [],
    bottomLine:             parsed.bottomLine             || ''
  }
}];

// ─────────────────────────────────────────────────────────────
// CALCULATE SAFETY SCORE
// Reads from riskBreakdown[] and missingProtectionsPlain[]
// which are the confirmed-present fields from Parse: Plain English
// ─────────────────────────────────────────────────────────────
const item = items[0];

const riskBreakdown          = item.json.riskBreakdown          || [];
const missingProtectionsPlain = item.json.missingProtectionsPlain || [];

// Count severities from riskBreakdown
const severityCounts = { CRITICAL: 0, HIGH: 0, MEDIUM: 0, LOW: 0 };
for (const risk of riskBreakdown) {
  const sev = (risk.severity || '').toUpperCase();
  if (sev in severityCounts) severityCounts[sev]++;
}

// Count missing protections by importance
let essentialMissing   = 0;
let recommendedMissing = 0;
let optionalMissing    = 0;
for (const m of missingProtectionsPlain) {
  const imp = (m.importance || '').toUpperCase();
  if      (imp === 'ESSENTIAL')    essentialMissing++;
  else if (imp === 'RECOMMENDED')  recommendedMissing++;
  else if (imp === 'OPTIONAL')     optionalMissing++;
}

// Deductions
const riskDeductions =
  severityCounts.CRITICAL * 40 +
  severityCounts.HIGH     * 20 +
  severityCounts.MEDIUM   * 10 +
  severityCounts.LOW      *  5;

const missingDeductions =
  essentialMissing   * 20 +
  recommendedMissing * 10 +
  optionalMissing    *  3;

// Final score clamped 0–100
const safetyScore = Math.max(0, Math.min(100, 100 - riskDeductions - missingDeductions));

// Grade
let grade, scoreLabel;
if      (safetyScore >= 80) { grade = 'A'; scoreLabel = 'LOW RISK';      }
else if (safetyScore >= 65) { grade = 'B'; scoreLabel = 'MODERATE RISK'; }
else if (safetyScore >= 50) { grade = 'C'; scoreLabel = 'ELEVATED RISK'; }
else if (safetyScore >= 35) { grade = 'D'; scoreLabel = 'HIGH RISK';     }
else                        { grade = 'F'; scoreLabel = 'CRITICAL RISK'; }

return [{
  json: {
    // carry all upstream fields
    sessionId:              item.json.sessionId,
    fileName:               item.json.fileName,
    fileType:               item.json.fileType,
    fileHash:               item.json.fileHash,
    uploadedAt:             item.json.uploadedAt,
    driveFileId:            item.json.driveFileId,
    documentText:           item.json.documentText,
    contractType:           item.json.contractType,
    confidence:             item.json.confidence,
    reasoning:              item.json.reasoning,
    extractedClauses:       item.json.extractedClauses,
    riskAnalysis:           item.json.riskAnalysis,
    missingProtections:     item.json.missingProtections,
    negotiationPriority:    item.json.negotiationPriority,
    plainEnglishSummary:    item.json.plainEnglishSummary,
    shouldSign:             item.json.shouldSign,
    topThreeActions:        item.json.topThreeActions,
    riskBreakdown,
    missingProtectionsPlain,
    bottomLine:             item.json.bottomLine,
    // score fields
    safetyScore,
    grade,
    scoreLabel,
    riskDeductions,
    missingDeductions,
    severityCounts,
    essentialMissing,
    recommendedMissing,
    optionalMissing
  }
}];

// ─────────────────────────────────────────────────────────────
// ASSEMBLE FINAL REPORT — HTML EMAIL VERSION
// ─────────────────────────────────────────────────────────────
const item = $input.first();
const d = item.json;

const {
  sessionId, fileName, fileType, fileHash, uploadedAt, driveFileId,
  contractType, confidence,
  extractedClauses = {},
  riskBreakdown = [],
  missingProtectionsPlain = [],
  plainEnglishSummary, shouldSign, topThreeActions = [], bottomLine,
  safetyScore, grade, scoreLabel,
  riskDeductions, missingDeductions,
  severityCounts = {},
  essentialMissing, recommendedMissing, optionalMissing,
} = d;

// ── Structured output ──────────────────────────────────────
const summary = {
  session_id: sessionId, file_name: fileName,
  file_type: (fileType || 'UNKNOWN').toUpperCase(),
  file_hash: fileHash, drive_file_id: driveFileId,
  analyzed_at: new Date().toISOString(), uploaded_at: uploadedAt,
  contract_type: contractType, classification_confidence: confidence,
  safety_score: safetyScore, grade, score_label: scoreLabel,
  should_sign: shouldSign, bottom_line: bottomLine,
};

const structuredOutput = {
  summary,
  key_clauses: extractedClauses,
  risks: riskBreakdown,
  missing_protections: missingProtectionsPlain,
  plain_english: { summary: plainEnglishSummary, shouldSign, topThreeActions, bottomLine },
  safety_score: { score: safetyScore, grade, scoreLabel, riskDeductions, missingDeductions, severityCounts, essentialMissing, recommendedMissing, optionalMissing }
};

// ── Colour helpers ─────────────────────────────────────────
function gradeColor(g) {
  return { A: '#16a34a', B: '#65a30d', C: '#d97706', D: '#ea580c', F: '#dc2626' }[g] || '#6b7280';
}
function severityColor(s) {
  return { CRITICAL: '#dc2626', HIGH: '#ea580c', MEDIUM: '#d97706', LOW: '#16a34a' }[(s||'').toUpperCase()] || '#6b7280';
}
function importanceColor(i) {
  return { ESSENTIAL: '#dc2626', RECOMMENDED: '#d97706', OPTIONAL: '#6b7280' }[(i||'').toUpperCase()] || '#6b7280';
}
function signColor(s) {
  if (!s) return '#6b7280';
  if (s.includes('NEGOTIATE')) return '#d97706';
  if (s.includes('DO NOT') || s.includes('REFUSE')) return '#dc2626';
  return '#16a34a';
}

// ── Score ring (SVG) ──────────────────────────────────────
const radius = 54;
const circ = 2 * Math.PI * radius;
const filled = circ * (safetyScore / 100);
const gap = circ - filled;
const scoreRing = `
<svg width="140" height="140" viewBox="0 0 140 140" xmlns="http://www.w3.org/2000/svg">
  <circle cx="70" cy="70" r="${radius}" fill="none" stroke="#e5e7eb" stroke-width="10"/>
  <circle cx="70" cy="70" r="${radius}" fill="none"
    stroke="${gradeColor(grade)}" stroke-width="10"
    stroke-dasharray="${filled} ${gap}"
    stroke-dashoffset="${circ * 0.25}"
    stroke-linecap="round"/>
  <text x="70" y="62" text-anchor="middle" font-family="Georgia,serif"
    font-size="28" font-weight="700" fill="${gradeColor(grade)}">${safetyScore}</text>
  <text x="70" y="80" text-anchor="middle" font-family="Georgia,serif"
    font-size="13" fill="#6b7280">/100</text>
  <text x="70" y="100" text-anchor="middle" font-family="Georgia,serif"
    font-size="16" font-weight="700" fill="${gradeColor(grade)}">${grade}</text>
</svg>`;

// ── Key Clauses rows ───────────────────────────────────────
const clauseRows = Object.entries(extractedClauses).map(([key, val]) => {
  const label = key.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase());
  let display = 'Not specified';
  if (val !== null && val !== undefined) {
    if (typeof val === 'object') {
      if (val.exists === false) display = '<span style="color:#9ca3af;font-style:italic;">Not found in contract</span>';
      else display = val.summary || val.details || val.schedule || val.method || JSON.stringify(val);
    } else display = val;
  }
  return `
  <tr>
    <td style="padding:10px 14px;font-family:Georgia,serif;font-size:13px;color:#6b7280;
               border-bottom:1px solid #f3f4f6;white-space:nowrap;vertical-align:top;
               font-weight:600;">${label}</td>
    <td style="padding:10px 14px;font-family:Georgia,serif;font-size:13px;color:#1f2937;
               border-bottom:1px solid #f3f4f6;">${display}</td>
  </tr>`;
}).join('');

// ── Risk cards ─────────────────────────────────────────────
const riskCards = riskBreakdown.length > 0
  ? riskBreakdown.map(r => {
      const sev = (r.severity || 'UNKNOWN').toUpperCase();
      const col = severityColor(sev);
      return `
  <div style="margin-bottom:14px;border:1px solid #e5e7eb;border-left:4px solid ${col};
              border-radius:6px;padding:14px 16px;background:#fff;">
    <div style="display:flex;align-items:center;gap:10px;margin-bottom:6px;">
      <span style="background:${col};color:#fff;font-family:Georgia,serif;font-size:11px;
                   font-weight:700;padding:2px 8px;border-radius:4px;letter-spacing:.5px;">${sev}</span>
      <span style="font-family:Georgia,serif;font-size:14px;font-weight:700;color:#111827;">${r.clause || ''}</span>
    </div>
    <p style="margin:0 0 8px;font-family:Georgia,serif;font-size:13px;color:#374151;line-height:1.6;">${r.plainEnglish || ''}</p>
    <div style="background:#f9fafb;border-radius:4px;padding:8px 12px;">
      <span style="font-family:Georgia,serif;font-size:12px;font-weight:700;color:#6b7280;
                   text-transform:uppercase;letter-spacing:.5px;">What to do: </span>
      <span style="font-family:Georgia,serif;font-size:12px;color:#374151;">${r.whatToDoAboutIt || ''}</span>
    </div>
  </div>`;
    }).join('')
  : `<p style="font-family:Georgia,serif;font-size:14px;color:#16a34a;font-style:italic;">No significant risks detected.</p>`;

// ── Missing protection cards ───────────────────────────────
const missingCards = missingProtectionsPlain.length > 0
  ? missingProtectionsPlain.map(m => {
      const imp = (m.importance || 'UNKNOWN').toUpperCase();
      const col = importanceColor(imp);
      return `
  <div style="margin-bottom:12px;border:1px solid #e5e7eb;border-left:4px solid ${col};
              border-radius:6px;padding:12px 16px;background:#fff;">
    <div style="display:flex;align-items:center;gap:10px;margin-bottom:5px;">
      <span style="background:${col};color:#fff;font-family:Georgia,serif;font-size:11px;
                   font-weight:700;padding:2px 8px;border-radius:4px;">${imp}</span>
      <span style="font-family:Georgia,serif;font-size:13px;font-weight:700;color:#111827;">${m.protection || ''}</span>
    </div>
    <p style="margin:0;font-family:Georgia,serif;font-size:13px;color:#374151;line-height:1.6;">${m.whyItMatters || ''}</p>
  </div>`;
    }).join('')
  : `<p style="font-family:Georgia,serif;font-size:14px;color:#16a34a;font-style:italic;">All key protections are present.</p>`;

// ── Top 3 Actions ──────────────────────────────────────────
const actionItems = topThreeActions.map((a, i) => `
  <div style="display:flex;gap:14px;margin-bottom:12px;align-items:flex-start;">
    <div style="min-width:28px;height:28px;background:#111827;color:#fff;border-radius:50%;
                display:flex;align-items:center;justify-content:center;
                font-family:Georgia,serif;font-size:13px;font-weight:700;flex-shrink:0;
                line-height:28px;text-align:center;">${i + 1}</div>
    <p style="margin:0;font-family:Georgia,serif;font-size:13px;color:#374151;line-height:1.7;
              padding-top:4px;">${a}</p>
  </div>`).join('');

// ── Score deduction rows ───────────────────────────────────
const deductionRows = [
  [severityCounts.CRITICAL, 'CRITICAL risks', 40, '#dc2626'],
  [severityCounts.HIGH,     'HIGH risks',     20, '#ea580c'],
  [severityCounts.MEDIUM,   'MEDIUM risks',   10, '#d97706'],
  [severityCounts.LOW,      'LOW risks',       5, '#16a34a'],
  [essentialMissing,   'ESSENTIAL missing',   20, '#dc2626'],
  [recommendedMissing, 'RECOMMENDED missing', 10, '#d97706'],
  [optionalMissing,    'OPTIONAL missing',     3, '#6b7280'],
].filter(([count]) => count > 0)
 .map(([count, label, pts, col]) => `
  <tr>
    <td style="padding:8px 12px;font-family:Georgia,serif;font-size:13px;color:#374151;
               border-bottom:1px solid #f3f4f6;">
      <span style="display:inline-block;width:10px;height:10px;background:${col};
                   border-radius:50%;margin-right:8px;vertical-align:middle;"></span>
      ${label} ×${count}
    </td>
    <td style="padding:8px 12px;font-family:Georgia,serif;font-size:13px;color:#dc2626;
               font-weight:700;border-bottom:1px solid #f3f4f6;text-align:right;">
      −${count * pts} pts
    </td>
  </tr>`).join('') || `
  <tr><td colspan="2" style="padding:8px 12px;font-family:Georgia,serif;font-size:13px;
    color:#16a34a;font-style:italic;">No deductions.</td></tr>`;

// ── Section header helper ──────────────────────────────────
function sectionHeader(num, title) {
  return `
  <tr>
    <td style="padding:28px 32px 10px;">
      <div style="display:flex;align-items:center;gap:12px;margin-bottom:4px;">
        <span style="font-family:Georgia,serif;font-size:11px;font-weight:700;color:#9ca3af;
                     letter-spacing:2px;text-transform:uppercase;">Section ${num}</span>
      </div>
      <h2 style="margin:0;font-family:Georgia,serif;font-size:18px;font-weight:700;
                 color:#111827;border-bottom:2px solid #111827;padding-bottom:8px;">${title}</h2>
    </td>
  </tr>`;
}

// ── HTML Email ─────────────────────────────────────────────
const emailBody = `<!DOCTYPE html>
<html lang="en">
<head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0">
<title>Contract Review Report</title></head>
<body style="margin:0;padding:0;background:#f3f4f6;font-family:Georgia,serif;">

<table width="100%" cellpadding="0" cellspacing="0" style="background:#f3f4f6;padding:32px 0;">
<tr><td align="center">
<table width="640" cellpadding="0" cellspacing="0" style="max-width:640px;width:100%;">

  <!-- HEADER -->
  <tr>
    <td style="background:#111827;border-radius:10px 10px 0 0;padding:28px 32px;">
      <p style="margin:0 0 4px;font-family:Georgia,serif;font-size:11px;font-weight:700;
                color:#9ca3af;letter-spacing:3px;text-transform:uppercase;">Contract Intelligence Report</p>
      <h1 style="margin:0 0 12px;font-family:Georgia,serif;font-size:22px;font-weight:700;color:#ffffff;">${fileName || 'Contract'}</h1>
      <span style="font-family:Georgia,serif;font-size:12px;color:#9ca3af;margin-right:16px;">📄 ${(fileType || 'UNKNOWN').toUpperCase()}</span>
      <span style="font-family:Georgia,serif;font-size:12px;color:#9ca3af;margin-right:16px;">🗂 ${contractType || 'Unknown Type'}</span>
      <span style="font-family:Georgia,serif;font-size:12px;color:#9ca3af;">🕒 ${new Date().toLocaleString()}</span>
    </td>
  </tr>

  <!-- SCORE BANNER -->
  <tr>
    <td style="background:#1f2937;padding:24px 32px;border-bottom:1px solid #374151;">
      <table width="100%" cellpadding="0" cellspacing="0">
        <tr>
          <td style="vertical-align:middle;" width="150">${scoreRing}</td>
          <td style="vertical-align:middle;padding-left:24px;">
            <p style="margin:0 0 6px;font-family:Georgia,serif;font-size:11px;font-weight:700;
                      color:#9ca3af;letter-spacing:2px;text-transform:uppercase;">Safety Assessment</p>
            <p style="margin:0 0 10px;font-family:Georgia,serif;font-size:22px;font-weight:700;
                      color:${gradeColor(grade)};">${scoreLabel}</p>
            <span style="background:${signColor(shouldSign)};display:inline-block;padding:6px 16px;
                      border-radius:20px;font-family:Georgia,serif;font-size:13px;font-weight:700;
                      color:#fff;letter-spacing:.5px;">${shouldSign}</span>
          </td>
        </tr>
      </table>
    </td>
  </tr>

  <!-- BOTTOM LINE -->
  <tr>
    <td style="background:#fef9c3;padding:16px 32px;border-bottom:2px solid #fde047;">
      <p style="margin:0;font-family:Georgia,serif;font-size:14px;color:#713f12;line-height:1.6;">
        <strong>⚠ Bottom Line:</strong> ${bottomLine}
      </p>
    </td>
  </tr>

  <!-- MAIN BODY -->
  <tr><td style="background:#ffffff;border-radius:0 0 10px 10px;">
    <table width="100%" cellpadding="0" cellspacing="0">

      ${sectionHeader(1, 'Contract Details')}
      <tr><td style="padding:0 32px 24px;">
        <table width="100%" cellpadding="0" cellspacing="0"
               style="border:1px solid #e5e7eb;border-radius:8px;overflow:hidden;">
          <tr style="background:#f9fafb;">
            <td style="padding:10px 14px;font-family:Georgia,serif;font-size:12px;font-weight:700;
                       color:#6b7280;letter-spacing:1px;text-transform:uppercase;width:36%;
                       border-bottom:1px solid #e5e7eb;">Field</td>
            <td style="padding:10px 14px;font-family:Georgia,serif;font-size:12px;font-weight:700;
                       color:#6b7280;letter-spacing:1px;text-transform:uppercase;
                       border-bottom:1px solid #e5e7eb;">Value</td>
          </tr>
          <tr>
            <td style="padding:10px 14px;font-family:Georgia,serif;font-size:13px;color:#6b7280;
                       font-weight:600;border-bottom:1px solid #f3f4f6;">Contract Type</td>
            <td style="padding:10px 14px;font-family:Georgia,serif;font-size:13px;color:#1f2937;
                       border-bottom:1px solid #f3f4f6;">${contractType}</td>
          </tr>
          <tr>
            <td style="padding:10px 14px;font-family:Georgia,serif;font-size:13px;color:#6b7280;
                       font-weight:600;border-bottom:1px solid #f3f4f6;">Confidence</td>
            <td style="padding:10px 14px;font-family:Georgia,serif;font-size:13px;color:#1f2937;
                       border-bottom:1px solid #f3f4f6;">${Math.round((confidence || 0) * 100)}%</td>
          </tr>
          ${clauseRows}
        </table>
      </td></tr>

      ${sectionHeader(2, 'Your Top 3 Actions')}
      <tr><td style="padding:0 32px 24px;">${actionItems}</td></tr>

      ${sectionHeader(3, 'Plain English Summary')}
      <tr><td style="padding:0 32px 24px;">
        <div style="background:#f9fafb;border-radius:8px;padding:16px 20px;border-left:4px solid #111827;">
          <p style="margin:0;font-family:Georgia,serif;font-size:14px;color:#374151;line-height:1.8;">
            ${plainEnglishSummary || 'No summary available.'}
          </p>
        </div>
      </td></tr>

      ${sectionHeader(4, `Risks & Warnings (${riskBreakdown.length} found)`)}
      <tr><td style="padding:0 32px 24px;">${riskCards}</td></tr>

      ${sectionHeader(5, `Missing Protections (${missingProtectionsPlain.length} found)`)}
      <tr><td style="padding:0 32px 24px;">${missingCards}</td></tr>

      ${sectionHeader(6, 'Score Breakdown')}
      <tr><td style="padding:0 32px 28px;">
        <table width="100%" cellpadding="0" cellspacing="0"
               style="border:1px solid #e5e7eb;border-radius:8px;overflow:hidden;">
          <tr style="background:#f9fafb;">
            <td style="padding:10px 12px;font-family:Georgia,serif;font-size:12px;font-weight:700;
                       color:#6b7280;letter-spacing:1px;text-transform:uppercase;
                       border-bottom:1px solid #e5e7eb;">Deduction Reason</td>
            <td style="padding:10px 12px;font-family:Georgia,serif;font-size:12px;font-weight:700;
                       color:#6b7280;letter-spacing:1px;text-transform:uppercase;
                       border-bottom:1px solid #e5e7eb;text-align:right;">Points</td>
          </tr>
          <tr>
            <td style="padding:10px 12px;font-family:Georgia,serif;font-size:13px;color:#374151;
                       border-bottom:1px solid #f3f4f6;">Base Score</td>
            <td style="padding:10px 12px;font-family:Georgia,serif;font-size:13px;font-weight:700;
                       color:#16a34a;border-bottom:1px solid #f3f4f6;text-align:right;">100 pts</td>
          </tr>
          ${deductionRows}
          <tr style="background:#f9fafb;">
            <td style="padding:12px;font-family:Georgia,serif;font-size:14px;font-weight:700;color:#111827;">Final Score</td>
            <td style="padding:12px;font-family:Georgia,serif;font-size:18px;font-weight:700;
                       color:${gradeColor(grade)};text-align:right;">${safetyScore}/100 — ${grade}</td>
          </tr>
        </table>
      </td></tr>

    </table>
  </td></tr>

  <!-- FOOTER -->
  <tr><td style="padding:20px 0;text-align:center;">
    <p style="margin:0;font-family:Georgia,serif;font-size:12px;color:#9ca3af;">
      Contract Review Agent · Powered by Claude (Anthropic)
    </p>
    <p style="margin:4px 0 0;font-family:Georgia,serif;font-size:11px;color:#d1d5db;">
      Session: ${sessionId || 'N/A'} · ${new Date().toISOString()}
    </p>
  </td></tr>

</table>
</td></tr>
</table>
</body></html>`;

return [{
  json: {
    sessionId,
    structuredOutput,
    emailBody,
    emailSubject: `Contract Review: ${fileName} — Score ${safetyScore}/100 [${grade} · ${scoreLabel}]`,
    safetyScore,
    grade,
    scoreLabel,
    shouldSign,
    contractType,
    riskCount: riskBreakdown.length,
    missingCount: missingProtectionsPlain.length,
    fileName
  }
}];
